def gen(rng, size):
    n = max(1, min(size, 4000))
    s = ''.join(rng.choice('AB') for _ in range(n))
    q_count = max(1, min(size, 4000))
    queries = []
    for _ in range(q_count):
        if rng.random() < 0.4:
            queries.append([1, rng.randint(0, n - 1)])
        else:
            l = rng.randint(0, n - 1)
            r = rng.randint(l, n - 1)
            queries.append([2, l, r])
    return [s, queries]

