class Solution:
    def minDeletions(self, s, queries):
        arr = list(s)
        res = []
        for q in queries:
            if q[0] == 1:
                j = q[1]
                arr[j] = 'B' if arr[j] == 'A' else 'A'
            else:
                l, r = q[1], q[2]
                sub = arr[l:r + 1]
                runs = 1
                for i in range(1, len(sub)):
                    if sub[i] != sub[i - 1]:
                        runs += 1
                res.append(len(sub) - runs)
        return res

