class Solution:
    def minDeletions(self, s, queries):
        n = len(s)
        arr = list(s)
        tree = [0] * (n + 1)
        def bit_update(i, delta):
            i += 1
            while i <= n:
                tree[i] += delta
                i += i & (-i)
        def bit_prefix(i):
            i += 1
            total = 0
            while i > 0:
                total += tree[i]
                i -= i & (-i)
            return total
        def range_sum(l, r):
            if r < l:
                return 0
            res = bit_prefix(r)
            if l > 0:
                res -= bit_prefix(l - 1)
            return res
        t = [0] * n
        for i in range(1, n):
            t[i] = 1 if arr[i] != arr[i - 1] else 0
            if t[i]:
                bit_update(i, 1)
        res = []
        for q in queries:
            if q[0] == 1:
                j = q[1]
                arr[j] = 'B' if arr[j] == 'A' else 'A'
                for idx in (j, j + 1):
                    if 1 <= idx < n:
                        newval = 1 if arr[idx] != arr[idx - 1] else 0
                        if newval != t[idx]:
                            bit_update(idx, newval - t[idx])
                            t[idx] = newval
            else:
                l, r = q[1], q[2]
                if l == r:
                    res.append(0)
                    continue
                runs = 1 + range_sum(l + 1, r)
                res.append((r - l + 1) - runs)
        return res

