var minDeletions = function(s, queries) {
    const n = s.length;
    const arr = s.split('');
    const tree = new Array(n + 1).fill(0);
    function bitUpdate(i, delta) {
        i += 1;
        while (i <= n) {
            tree[i] += delta;
            i += i & (-i);
        }
    }
    function bitPrefix(i) {
        i += 1;
        let total = 0;
        while (i > 0) {
            total += tree[i];
            i -= i & (-i);
        }
        return total;
    }
    function rangeSum(l, r) {
        if (r < l) return 0;
        let res = bitPrefix(r);
        if (l > 0) res -= bitPrefix(l - 1);
        return res;
    }
    const t = new Array(n).fill(0);
    for (let i = 1; i < n; i++) {
        t[i] = arr[i] !== arr[i - 1] ? 1 : 0;
        if (t[i]) bitUpdate(i, 1);
    }
    const res = [];
    for (const q of queries) {
        if (q[0] === 1) {
            const j = q[1];
            arr[j] = arr[j] === 'A' ? 'B' : 'A';
            for (const idx of [j, j + 1]) {
                if (idx >= 1 && idx < n) {
                    const newval = arr[idx] !== arr[idx - 1] ? 1 : 0;
                    if (newval !== t[idx]) {
                        bitUpdate(idx, newval - t[idx]);
                        t[idx] = newval;
                    }
                }
            }
        } else {
            const l = q[1], r = q[2];
            if (l === r) {
                res.push(0);
                continue;
            }
            const runs = 1 + rangeSum(l + 1, r);
            res.push((r - l + 1) - runs);
        }
    }
    return res;
};
